exercise.solutionCode:
public class Main {

    public static double calculateDiscount(double price) {
        return price * 0.10;
    }

    public static double calculateDiscount(double price, double rate) {
        return price * rate;
    }

    public static double calculateDiscount(double price, double rate, String code) {
        double discount = price * rate;
        if (code.equals("EXTRA")) return discount * 1.05;
        return discount;
    }

    public static void main(String[] args) {
        System.out.printf("Default 10%%: Rs %.2f%n",  calculateDiscount(2000.0));
        System.out.printf("Custom 20%%: Rs %.2f%n",   calculateDiscount(2000.0, 0.20));
        System.out.printf("EXTRA code: Rs %.2f%n",    calculateDiscount(2000.0, 0.20, "EXTRA"));
    }
}
